def update_availability(doctype, asset_name, link_field):
    if not asset_name:
        return

    repairs = frappe.get_all(
        "Repair Job",
        filters={
            link_field: asset_name,
            "priority": ["in", ["Medium", "High", "Urgent"]],
            "status": ["not in", ["Completed", "Cancelled"]]
        },
        limit=1
    )

    frappe.db.set_value(
        doctype,
        asset_name,
        "availability_status",
        "Unavailable" if repairs else "Available",
        update_modified=False
    )


# Update current asset
if doc.asset_type == "Club Boat":
    update_availability("Club Boats", doc.boat, "boat")

elif doc.asset_type == "Machinery":
    update_availability("Machinery", doc.machinery, "machinery")


# If the asset changed, update the old one too
if not doc.is_new():
    old = doc.get_doc_before_save()

    if old:
        if old.asset_type == "Club Boat" and old.boat != doc.boat:
            update_availability("Club Boats", old.boat, "boat")

        elif old.asset_type == "Machinery" and old.machinery != doc.machinery:
            update_availability("Machinery", old.machinery, "machinery")

